import { get, set, del } from "idb-keyval";
import type { ProviderId } from "./providerConfig";

/**
 * BYOK keys are encrypted at rest in IndexedDB using a non-extractable
 * AES-GCM CryptoKey generated by the Web Crypto API. The CryptoKey object
 * itself (not its raw bytes) is stored via structured clone in IndexedDB —
 * because it's non-extractable, copying the IndexedDB files to another
 * machine or origin yields an unusable key handle. This does NOT protect
 * against same-origin XSS (nothing client-side can), only against naive
 * at-rest inspection of the browser's storage. See docs/BYOK.md.
 */

const CRYPTO_KEY_STORAGE_KEY = "kiln:byok:cryptokey";
const keyStorageKey = (provider: ProviderId) => `kiln:byok:key:${provider}`;

interface EncryptedBlob {
  iv: number[];
  ciphertext: number[];
}

async function getOrCreateCryptoKey(): Promise<CryptoKey> {
  const existing = await get<CryptoKey>(CRYPTO_KEY_STORAGE_KEY);
  if (existing) return existing;

  const key = await crypto.subtle.generateKey({ name: "AES-GCM", length: 256 }, false, ["encrypt", "decrypt"]);
  await set(CRYPTO_KEY_STORAGE_KEY, key);
  return key;
}

export async function saveApiKey(provider: ProviderId, plaintext: string): Promise<void> {
  const cryptoKey = await getOrCreateCryptoKey();
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const encoded = new TextEncoder().encode(plaintext);
  const ciphertext = await crypto.subtle.encrypt({ name: "AES-GCM", iv }, cryptoKey, encoded);

  const blob: EncryptedBlob = {
    iv: Array.from(iv),
    ciphertext: Array.from(new Uint8Array(ciphertext)),
  };
  await set(keyStorageKey(provider), blob);
}

export async function loadApiKey(provider: ProviderId): Promise<string | null> {
  const blob = await get<EncryptedBlob>(keyStorageKey(provider));
  if (!blob) return null;

  const cryptoKey = await getOrCreateCryptoKey();
  const iv = new Uint8Array(blob.iv);
  const ciphertext = new Uint8Array(blob.ciphertext);

  try {
    const plaintext = await crypto.subtle.decrypt({ name: "AES-GCM", iv }, cryptoKey, ciphertext);
    return new TextDecoder().decode(plaintext);
  } catch {
    return null; // key rotated or blob corrupted — treat as absent, never throw a decrypt error to the UI
  }
}

export async function removeApiKey(provider: ProviderId): Promise<void> {
  await del(keyStorageKey(provider));
}

export async function hasApiKey(provider: ProviderId): Promise<boolean> {
  return (await get(keyStorageKey(provider))) !== undefined;
}
